// Single source of truth for the project logo. Edit the MOTIF parameters
// below, run `node scripts/generate-logo-assets.mjs`, and both artifacts
// are rewritten: assets/logo.svg (repo preview / directory listings) and
// packages/gw-worker/src/logo.generated.ts (served at /logo.svg and
// /favicon.ico). Never edit the generated files by hand.
//
// Motif: a golden scythe-blade crescent on a dark disc — a nod to the
// Dervish and to Nightfall. The crescent is circle A minus circle B; the
// ICO is rasterized from the exact same geometry (4x4 supersampling), so
// the favicon can never drift from the logo.
import { writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const MOTIF = {
  view: 64,
  disc: { color: "#1e1b22" },
  gold: "#d4af37",
  bladeA: { cx: 30, cy: 30, r: 22 },
  bladeB: { cx: 37, cy: 34, r: 21 },
};

function buildSvg() {
  const { view, disc, gold, bladeA: a, bladeB: b } = MOTIF;
  const h = view / 2;
  return (
    `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${view} ${view}">` +
    `<circle cx="${h}" cy="${h}" r="${h}" fill="${disc.color}"/>` +
    `<circle cx="${a.cx}" cy="${a.cy}" r="${a.r}" fill="${gold}"/>` +
    `<circle cx="${b.cx}" cy="${b.cy}" r="${b.r}" fill="${disc.color}"/>` +
    `</svg>\n`
  );
}

function hexToRgb(hex) {
  return [1, 3, 5].map((i) => parseInt(hex.slice(i, i + 2), 16));
}

/** Rasterize the motif to a 16x16 32-bit ICO — pure math, no dependencies. */
function buildIco() {
  const SIZE = 16;
  const SS = 4; // supersampling grid per pixel side
  const scale = MOTIF.view / SIZE;
  const disc = hexToRgb(MOTIF.disc.color);
  const gold = hexToRgb(MOTIF.gold);
  const { bladeA: a, bladeB: b } = MOTIF;
  const half = MOTIF.view / 2;
  const inside = (x, y, cx, cy, r) => (x - cx) ** 2 + (y - cy) ** 2 <= r * r;

  const px = []; // rows of [r,g,b,alpha]
  for (let y = 0; y < SIZE; y++) {
    const row = [];
    for (let x = 0; x < SIZE; x++) {
      let cov = 0;
      let goldHits = 0;
      for (let sy = 0; sy < SS; sy++) {
        for (let sx = 0; sx < SS; sx++) {
          const ux = (x + (sx + 0.5) / SS) * scale;
          const uy = (y + (sy + 0.5) / SS) * scale;
          if (!inside(ux, uy, half, half, half)) continue;
          cov++;
          if (inside(ux, uy, a.cx, a.cy, a.r) && !inside(ux, uy, b.cx, b.cy, b.r)) goldHits++;
        }
      }
      const total = SS * SS;
      const alpha = Math.round((cov / total) * 255);
      const t = cov === 0 ? 0 : goldHits / cov;
      const mix = (i) => Math.round(disc[i] + (gold[i] - disc[i]) * t);
      row.push([mix(0), mix(1), mix(2), alpha]);
    }
    px.push(row);
  }

  const imageSize = 40 + SIZE * SIZE * 4 + SIZE * 4; // header + BGRA + AND mask
  const buf = Buffer.alloc(6 + 16 + imageSize);
  // ICONDIR
  buf.writeUInt16LE(1, 2); // type: icon
  buf.writeUInt16LE(1, 4); // count
  // ICONDIRENTRY
  buf.writeUInt8(SIZE, 6);
  buf.writeUInt8(SIZE, 7);
  buf.writeUInt16LE(1, 10); // planes
  buf.writeUInt16LE(32, 12); // bpp
  buf.writeUInt32LE(imageSize, 14);
  buf.writeUInt32LE(22, 18); // offset
  // BITMAPINFOHEADER
  let o = 22;
  buf.writeUInt32LE(40, o);
  buf.writeInt32LE(SIZE, o + 4);
  buf.writeInt32LE(SIZE * 2, o + 8); // XOR + AND height
  buf.writeUInt16LE(1, o + 12);
  buf.writeUInt16LE(32, o + 14);
  o += 40;
  // pixels, bottom-up, BGRA
  for (let y = SIZE - 1; y >= 0; y--) {
    for (let x = 0; x < SIZE; x++) {
      const [r, g, bl, alpha] = px[y][x];
      buf.writeUInt8(bl, o++);
      buf.writeUInt8(g, o++);
      buf.writeUInt8(r, o++);
      buf.writeUInt8(alpha, o++);
    }
  }
  // AND mask stays zeroed (alpha channel rules)
  return buf;
}

function main() {
  const root = join(dirname(fileURLToPath(import.meta.url)), "..");
  const svg = buildSvg();
  const ico = buildIco();
  writeFileSync(join(root, "assets/logo.svg"), svg);
  const gen =
    "// GENERATED by scripts/generate-logo-assets.mjs — do not edit.\n" +
    "// Source of truth: the MOTIF parameters in that script.\n" +
    `export const LOGO_SVG = ${JSON.stringify(svg.trim())};\n` +
    `export const FAVICON_ICO_B64 = ${JSON.stringify(ico.toString("base64"))};\n`;
  writeFileSync(join(root, "packages/gw-worker/src/logo.generated.ts"), gen);
  console.log(`logo.svg ${svg.length}B, favicon ${ico.length}B — regenerated`);
}

const isDirectRun = import.meta.url === `file://${process.argv[1]}`;
if (isDirectRun) main();
